100→            <Route path='/home' element={<HomePage/>}>
101→              <Route index element={<PostCards/>}/>
102→              <Route path='explore' element={<ExplorePage/>}/>
103→              <Route path='gallery' element={<GalleryPage/>}/>
104→              <Route path='freedom-wall' element={<FreedomWallPage/>}/>
105→              <Route path='contentViewer' element={<ContentView/>}/>
106→              <Route path='post/:journalId' element={<ContentView/>}/>
107→              <Route path='post/:journalId/:slug' element={<ContentView/>}/>
108→              <Route path='bookmark' element={<Bookmarks/>}/>
109→              <Route path='userCollections' element={<ViewUserCollection/>}/>
110→              <Route path='opinions'element={<OpinionsPage/>}/>
111→              <Route path='opinionsViewer' element={<OpinionViewer/>}/>
112→
113→              <Route path='collections' element={<Collections/>}/>
114→              <Route path='collectionCards' element={<CollectionJournals/>}/>
115→              
116→              {/* route for nested notifications */}
117→              <Route path='notifications' element={<Notifications/>}>
